protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Preserve EF8 discriminator property name ("Discriminator" instead of EF9 default "$type")
    // so existing documents and raw SQL queries using c.Discriminator keep working.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Preserve EF8 compound id format ("Blog|1") so existing documents remain accessible.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // HasIndex removed — Cosmos DB provider now throws at startup.
    // Manage indexing via the container's indexing policy (Azure Portal / Bicep / Terraform).
}

